import{_ as i,W as r,X as l,Y as o,Z as e,$ as a,a0 as s,a1 as n,C as c}from"./framework-a4c02b8f.js";const d="/assets/images/MulticastWithoutIGMP.png",p={},h=e("p",null,"IGMP 是一个网络层协议，用于在 IPv4 的网络上设置多播。",-1),u=e("p",null,"具体来说，IGMP 允许设备加入一个多播组。",-1),m=n(`<h2 id="什么是多播-multicast" tabindex="-1"><a class="header-anchor" href="#什么是多播-multicast" aria-hidden="true">#</a> 什么是多播（Multicast）？</h2><p>多播使得一个应用可以仅仅发送一个数据包，就能让网络中的一组 host 都收到，就像群发邮件一样。</p><p>多播通过在多个设备之间共享 IP 地址来运作。指向该 IP 地址的任何网络流量都将到达共享该 IP 地址的所有设备。</p><p>因为多播是一对多的，所以只能用类似 SOCK_DGRAM 的 socket，而不能用 SOCK_STREAM。</p><h2 id="igmp-如何运作" tabindex="-1"><a class="header-anchor" href="#igmp-如何运作" aria-hidden="true">#</a> IGMP 如何运作？</h2><p>连接到网络的计算机和其他设备在想要加入多播组时使用 IGMP。支持 IGMP 的路由器侦听来自设备的 IGMP 传输，以确定哪些设备属于哪些多播组。</p><p>IGMP 使用为多播预留的 IP 地址。多播 IP 地址在 224.0.0.0 和 239.255.255.255 之间的范围内（即D类网段）。并被分为</p><ul><li>局部多播地址：在 224.0.0.0～224.0.0.255 之间，这是为路由协议和其他用途保留的地址，路由器并不转发属于此范围的 IP 包。</li><li>预留多播地址：在 224.0.1.0～238.255.255.255 之间，可用于全球范围（如 Internet ）或网络协议。</li><li>管理权限多播地址：在 239.0.0.0～239.255.255.255 之间，可供组织内部使用，类似于私有IP地址，不能用于 Internet，可限制多播范围。</li></ul><p>每个多播组共享其中一个 IP 地址。当路由器接收到一系列指向该共享 IP 地址的数据包时，它将复制这些数据包，将副本发送给多播组的所有成员。 IGMP 多播组可以随时更改。设备可以在任何时候发送 IGMP “加入组”或“离开组”消息。IGMP 不限成员数量和位置。</p><h2 id="使用" tabindex="-1"><a class="header-anchor" href="#使用" aria-hidden="true">#</a> 使用</h2><h3 id="命令行" tabindex="-1"><a class="header-anchor" href="#命令行" aria-hidden="true">#</a> 命令行</h3><p><strong>加入指定多播组</strong></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> <span class="token function">ip</span> addr <span class="token function">add</span> <span class="token number">233.54</span>.12.234/32 dev eth1 autojoin
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>或者</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>socat STDIO UDP4-RECV:22001,ip-add-membership<span class="token operator">=</span><span class="token number">233.54</span>.12.234:eth1 <span class="token operator">&gt;</span> /dev/null
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>查看加入了哪些多播组</strong></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">netstat</span> <span class="token parameter variable">-gn</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="程序" tabindex="-1"><a class="header-anchor" href="#程序" aria-hidden="true">#</a> 程序</h3><p>setsockopt()参数</p><ol><li>IP_ADD_MEMBERSHIP: 加入指定多播组</li><li>IP_DROP_MEMBERSHIP: 退出指定多播组</li><li>IP_MULTICAST_IF: 设置将要发出multicast包的interface</li><li>IP_MULTICAST_TTL: 设置发出的multicast包的TTL，默认TTL为1。</li><li>IP_MULTICAST_LOOP: 设置是否要将发出的multicast包也发给发送者，如果发送者也是那个多播组的一员。</li></ol>`,20),_={href:"https://tldp.org/HOWTO/Multicast-HOWTO-6.html",target:"_blank",rel:"noopener noreferrer"},g=n('<p>一般要写一个收/发multicast的程序，需要：</p><ol><li>建立一个socket。</li><li>设置多播的参数，例如超时时间TTL、本地回环许可LOOP等。（纯接收的话不用设置）</li><li>加入多播组。</li><li>发送或接收数据。</li><li>退出多播组。</li></ol><h2 id="multicast-without-igmp" tabindex="-1"><a class="header-anchor" href="#multicast-without-igmp" aria-hidden="true">#</a> Multicast Without IGMP</h2><p>在实际使用中，我们发现，在有些机器上，即使我们没有加入多播组，也能收到多播信息。</p><figure><img src="'+d+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>这是由于接收者和发送源在<strong>同一内网</strong>下，所以不需要加入多播组就能收到multicast。</p><h2 id="参考" tabindex="-1"><a class="header-anchor" href="#参考" aria-hidden="true">#</a> 参考</h2>',7),I={href:"https://www.cloudflare.com/zh-cn/learning/network-layer/what-is-igmp/",target:"_blank",rel:"noopener noreferrer"},f={href:"https://www.tenouk.com/Module41c.html",target:"_blank",rel:"noopener noreferrer"},P={href:"https://unix.stackexchange.com/questions/140384/creating-multicast-join-for-tcpdump-captures",target:"_blank",rel:"noopener noreferrer"},b={href:"https://superuser.com/questions/425665/multicast-streaming-without-igmp",target:"_blank",rel:"noopener noreferrer"};function M(k,v){const t=c("ExternalLinkIcon");return r(),l("div",null,[h,u,o(" more "),m,e("p",null,[a("具体使用可见："),e("a",_,[a("https://tldp.org/HOWTO/Multicast-HOWTO-6.html"),s(t)])]),g,e("ul",null,[e("li",null,[e("a",I,[a("https://www.cloudflare.com/zh-cn/learning/network-layer/what-is-igmp/"),s(t)])]),e("li",null,[e("a",f,[a("https://www.tenouk.com/Module41c.html"),s(t)])]),e("li",null,[e("a",P,[a("https://unix.stackexchange.com/questions/140384/creating-multicast-join-for-tcpdump-captures"),s(t)])]),e("li",null,[e("a",b,[a("https://superuser.com/questions/425665/multicast-streaming-without-igmp"),s(t)])])])])}const T=i(p,[["render",M],["__file","Multicast_and_IGMP.html.vue"]]);export{T as default};
